const items = $input.all();
const results = [];

for (const item of items) {
  const data = item.json;

  const name = data['ชื่อ-สกุล'] || 'ไม่ระบุ';
  const dept = data['แผนก'] || 'ไม่ระบุ';
  const equipment = data['รายชื่ออุปกรณ์'] || 'ไม่ระบุ';
  const qty = data['จำนวนที่เบิก'] || '0';
  const date = data['ประทับเวลา'] || new Date().toISOString();

  const subject = `แจ้งเตือน: การเบิกอุปกรณ์ - ${name}`;

  const message = `<div style="font-family: Arial, sans-serif; max-width: 600px; margin: 0 auto;">`
    + `<div style="background: linear-gradient(135deg, #667eea 0%, #764ba2 100%); padding: 30px; border-radius: 12px 12px 0 0;">`
    + `<h2 style="color: white; margin: 0;">📋 แจ้งเตือนการเบิกอุปกรณ์</h2>`
    + `</div>`
    + `<div style="background: #ffffff; padding: 30px; border: 1px solid #e0e0e0; border-radius: 0 0 12px 12px;">`
    + `<table style="width: 100%; border-collapse: collapse;">`
    + `<tr><td style="padding: 12px; border-bottom: 1px solid #f0f0f0; color: #666; width: 40%;">👤 ผู้ขอเบิก</td><td style="padding: 12px; border-bottom: 1px solid #f0f0f0; font-weight: bold;">${name}</td></tr>`
    + `<tr><td style="padding: 12px; border-bottom: 1px solid #f0f0f0; color: #666;">🏢 แผนก</td><td style="padding: 12px; border-bottom: 1px solid #f0f0f0; font-weight: bold;">${dept}</td></tr>`
    + `<tr><td style="padding: 12px; border-bottom: 1px solid #f0f0f0; color: #666;">🔧 อุปกรณ์</td><td style="padding: 12px; border-bottom: 1px solid #f0f0f0; font-weight: bold;">${equipment}</td></tr>`
    + `<tr><td style="padding: 12px; border-bottom: 1px solid #f0f0f0; color: #666;">📦 จำนวน</td><td style="padding: 12px; border-bottom: 1px solid #f0f0f0; font-weight: bold;">${qty}</td></tr>`
    + `<tr><td style="padding: 12px; color: #666;">📅 วันที่เบิก</td><td style="padding: 12px; font-weight: bold;">${date}</td></tr>`
    + `</table>`
    + `<hr style="border: none; border-top: 1px solid #f0f0f0; margin: 20px 0;">`
    + `<p style="color: #999; font-size: 12px; text-align: center;">ระบบแจ้งเตือนอัตโนมัติจาก n8n - Project 67708153</p>`
    + `</div></div>`;

  results.push({
    json: {
      subject: subject,
      message: message,
      name: name,
      dept: dept,
      equipment: equipment,
      qty: qty,
      date: date
    }
  });
}

return results;
